import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from "../types";
import { Logger } from "./monitoringService";

const getAIClient = () => {
    const apiKey = process.env.API_KEY || (import.meta as any).env?.VITE_GEMINI_API_KEY;
    if (!apiKey) throw new Error("API Key missing");
    return new GoogleGenAI({ apiKey });
};

export const parseEmailBatch = async (emails: { id: string, snippet: string, body: string, date: string, subject: string }[]): Promise<Transaction[]> => {
    if (emails.length === 0) return [];

    try {
        const ai = getAIClient();

        // Prepara o prompt com lote de e-mails para economizar chamadas
        const emailData = emails.map(e => `
        --- EMAIL ID: ${e.id} ---
        DATA: ${e.date}
        ASSUNTO: ${e.subject}
        CONTEÚDO: ${e.snippet} ... ${e.body.substring(0, 500)}
        -------------------------
        `).join('\n');

        const prompt = `
        Você é um extrator financeiro especializado em e-mails bancários brasileiros (Pix, Transferências).
        Analise os e-mails abaixo e extraia as transações financeiras válidas.

        INPUT:
        ${emailData}

        REGRAS:
        1. Ignore e-mails de propaganda, segurança ou avisos gerais.
        2. Extraia apenas e-mails de confirmação de transação (Entrada ou Saída).
        3. Para "Entradas" (Pix Recebido), o valor deve ser POSITIVO.
        4. Para "Saídas" (Pix Enviado, Pagamento), o valor deve ser NEGATIVO.
        5. A data deve ser convertida para o formato YYYY-MM-DD.
        6. A descrição deve conter o nome do pagador/recebedor ou a descrição do Pix. Limpe textos como "Pix recebido de".

        Retorne um JSON Array.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0.1,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING, description: "O ID original do e-mail" },
                            date: { type: Type.STRING, description: "YYYY-MM-DD" },
                            description: { type: Type.STRING },
                            amount: { type: Type.NUMBER },
                            type: { type: Type.STRING, description: "PIX, TED, BOLETO, etc" }
                        },
                        required: ["id", "date", "description", "amount"]
                    }
                }
            }
        });

        const extracted = response.text ? JSON.parse(response.text) : [];

        // Converte para o tipo Transaction interno
        return extracted.map((item: any) => ({
            id: `gmail-${item.id}`,
            date: item.date,
            description: item.description,
            cleanedDescription: item.description, // Será limpo novamente pelo pipeline principal
            amount: item.amount,
            originalAmount: String(item.amount),
            contributionType: item.type || 'PIX'
        }));

    } catch (error) {
        Logger.error("Erro ao parsear e-mails com IA", error);
        return [];
    }
};

import { Logger } from "./monitoringService";
import { supabase } from "./supabaseClient";

// Escopos necessários
const GMAIL_SCOPES = 'https://www.googleapis.com/auth/gmail.readonly';

export const gmailService = {

    /**
     * Inicia o fluxo de autenticação para obter o token do Gmail.
     * Utiliza o Supabase Auth com escopos adicionais.
     */
    connect: async () => {
        const { error } = await supabase.auth.signInWithOAuth({
            provider: 'google',
            options: {
                scopes: GMAIL_SCOPES,
                redirectTo: window.location.origin,
                queryParams: {
                    access_type: 'offline',
                    prompt: 'consent', // Força refresh token se necessário
                }
            }
        });
        if (error) throw error;
    },

    /**
     * Busca e-mails bancários recentes.
     * Requer que o usuário já tenha feito login com o escopo correto.
     */
    fetchBankEmails: async (accessToken: string, maxResults = 20) => {
        try {
            // 1. Listar Mensagens (Filtro por keywords bancárias comuns)
            const query = 'subject:(pix OR transferência OR comprovante OR recebido OR enviado) -category:promotions -category:social';
            const listUrl = `https://gmail.googleapis.com/gmail/v1/users/me/messages?q=${encodeURIComponent(query)}&maxResults=${maxResults}`;

            const listResponse = await fetch(listUrl, {
                headers: { Authorization: `Bearer ${accessToken}` }
            });

            if (!listResponse.ok) {
                if (listResponse.status === 401) throw new Error("Token expirado ou inválido.");
                throw new Error("Falha ao listar e-mails.");
            }

            const listData = await listResponse.json();
            if (!listData.messages || listData.messages.length === 0) return [];

            // 2. Buscar Detalhes de cada mensagem (Batch requests seria ideal, mas fetch paralelo funciona para poucos itens)
            const messages = await Promise.all(listData.messages.map(async (msg: any) => {
                const detailUrl = `https://gmail.googleapis.com/gmail/v1/users/me/messages/${msg.id}?format=full`;
                const detailResponse = await fetch(detailUrl, {
                    headers: { Authorization: `Bearer ${accessToken}` }
                });
                return detailResponse.json();
            }));

            // 3. Simplificar Payload para a IA
            return messages.map((msg: any) => {
                const headers = msg.payload.headers;
                const subject = headers.find((h: any) => h.name === 'Subject')?.value || '';
                const date = headers.find((h: any) => h.name === 'Date')?.value || '';
                const snippet = msg.snippet;

                // Tenta extrair corpo texto (preferência text/plain)
                let body = '';
                if (msg.payload.parts) {
                    const part = msg.payload.parts.find((p: any) => p.mimeType === 'text/plain');
                    if (part && part.body.data) {
                        body = atob(part.body.data.replace(/-/g, '+').replace(/_/g, '/'));
                    }
                } else if (msg.payload.body.data) {
                    body = atob(msg.payload.body.data.replace(/-/g, '+').replace(/_/g, '/'));
                }

                return {
                    id: msg.id,
                    subject,
                    date,
                    snippet,
                    body
                };
            });

        } catch (error) {
            Logger.error("Erro no serviço Gmail", error);
            throw error;
        }
    }
};

import React, { useContext, useEffect, useState } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { XMarkIcon, EnvelopeIcon, BoltIcon, CheckCircleIcon, ExclamationTriangleIcon, GoogleIcon, SparklesIcon } from '../Icons';
import { gmailService } from '../../services/gmailService';
import { parseEmailBatch } from '../../services/emailParser';
import { supabase } from '../../services/supabaseClient';

interface GmailSyncModalProps {
    onClose: () => void;
}

export const GmailSyncModal: React.FC<GmailSyncModalProps> = ({ onClose }) => {
    const { 
        handleGmailSyncSuccess, // Nova função no context
        banks 
    } = useContext(AppContext);
    const { t } = useTranslation();

    const [status, setStatus] = useState<'idle' | 'auth' | 'fetching' | 'analyzing' | 'success' | 'error'>('idle');
    const [log, setLog] = useState<string[]>([]);
    const [foundCount, setFoundCount] = useState(0);

    const addLog = (msg: string) => setLog(prev => [...prev, msg]);

    const startSync = async () => {
        setStatus('auth');
        addLog("Verificando sessão...");

        try {
            const { data: { session } } = await supabase.auth.getSession();

            // Tenta obter o token do provedor. 
            // Nota: O Supabase só expõe o provider_token na sessão inicial ou se configurado explicitamente.
            // Se falhar, pedimos re-login.
            let token = session?.provider_token;

            if (!token) {
                addLog("Token não encontrado. Solicitando permissão...");
                await gmailService.connect(); // Isso redirecionará a página
                return;
            }

            setStatus('fetching');
            addLog("Buscando e-mails bancários recentes...");
            const emails = await gmailService.fetchBankEmails(token, 15); // Limite de 15 para teste rápido

            if (emails.length === 0) {
                addLog("Nenhum e-mail relevante encontrado.");
                setStatus('error');
                return;
            }

            addLog(`${emails.length} e-mails encontrados. Analisando com IA...`);
            setStatus('analyzing');

            const transactions = await parseEmailBatch(emails);
            setFoundCount(transactions.length);

            if (transactions.length > 0) {
                addLog(`${transactions.length} transações identificadas!`);
                handleGmailSyncSuccess(transactions); // Injeta no sistema
                setStatus('success');
            } else {
                addLog("A IA não conseguiu extrair transações válidas.");
                setStatus('error');
            }

        } catch (error: any) {
            console.error(error);
            addLog(`Erro: ${error.message}`);
            setStatus('error');
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-2xl w-full max-w-md border border-slate-200 dark:border-slate-700 overflow-hidden animate-scale-in">

                {/* Header */}
                <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/30">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-red-50 dark:bg-red-900/20 rounded-xl text-red-600 dark:text-red-400 border border-red-100 dark:border-red-800">
                            <EnvelopeIcon className="w-5 h-5" />
                        </div>
                        <div>
                            <h3 className="text-lg font-black text-slate-800 dark:text-white tracking-tight">Importar do Gmail</h3>
                            <p className="text-[10px] text-slate-500 dark:text-slate-400 font-medium">Automação Inteligente v1.0</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                        <XMarkIcon className="w-5 h-5" />
                    </button>
                </div>

                {/* Body */}
                <div className="p-8">
                    {status === 'idle' && (
                        <div className="text-center space-y-6">
                            <div className="w-16 h-16 bg-blue-50 dark:bg-blue-900/20 rounded-full flex items-center justify-center mx-auto mb-4">
                                <GoogleIcon className="w-8 h-8" />
                            </div>
                            <p className="text-sm text-slate-600 dark:text-slate-300">
                                Conecte seu Gmail para que a IA busque automaticamente comprovantes de Pix e transferências recentes.
                            </p>
                            <div className="bg-amber-50 dark:bg-amber-900/20 p-3 rounded-xl border border-amber-100 dark:border-amber-800 text-left">
                                <p className="text-[10px] text-amber-700 dark:text-amber-300 flex gap-2">
                                    <ExclamationTriangleIcon className="w-4 h-4 shrink-0" />
                                    <span>
                                        O sistema lerá apenas e-mails com termos como "Pix", "Comprovante" ou "Transferência". Nenhum dado pessoal será armazenado.
                                    </span>
                                </p>
                            </div>
                            <button 
                                onClick={startSync}
                                className="w-full py-3 bg-brand-blue hover:bg-blue-600 text-white rounded-xl font-bold uppercase tracking-wide shadow-lg shadow-blue-500/30 transition-all active:scale-95 flex items-center justify-center gap-2"
                            >
                                <BoltIcon className="w-4 h-4" />
                                Conectar e Sincronizar
                            </button>
                        </div>
                    )}

                    {(status === 'auth' || status === 'fetching' || status === 'analyzing') && (
                        <div className="text-center py-8">
                            <div className="relative w-16 h-16 mx-auto mb-6">
                                <div className="absolute inset-0 border-4 border-slate-100 dark:border-slate-700 rounded-full"></div>
                                <div className="absolute inset-0 border-4 border-brand-blue border-t-transparent rounded-full animate-spin"></div>
                                <div className="absolute inset-0 flex items-center justify-center">
                                    <SparklesIcon className="w-6 h-6 text-brand-blue animate-pulse" />
