import { Logger } from "../../services/monitoringService";

export interface GmailTransaction {
    date: string;
    description: string;
    amount: number;
    type?: string;
}

export const gmailService = {
    /**
     * Envia o token para o backend processar os e-mails de forma segura.
     * NENHUM processamento de dados ou IA ocorre no frontend.
     */
    syncEmails: async (accessToken: string): Promise<GmailTransaction[]> => {
        try {
            const response = await fetch('/api/gmail/sync', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ accessToken })
            });

            if (!response.ok) {
                const errorText = await response.text();
                throw new Error(`Erro no servidor: ${errorText}`);
            }

            const data = await response.json();

            if (!data.transactions || !Array.isArray(data.transactions)) {
                return [];
            }

            return data.transactions;
        } catch (error) {
            Logger.error("Erro ao sincronizar Gmail", error);
            throw error;
        }
    }
};

import { GmailTransaction } from "./GmailService";

/**
 * Converte as transações estruturadas do Gmail em uma string CSV.
 * Isso permite injetar os dados no pipeline existente (StrategyEngine)
 * sem precisar modificar a lógica de upload ou reconciliação do AppContext.
 */
export const adaptGmailToCsv = (transactions: GmailTransaction[]): string => {
    if (transactions.length === 0) return "";

    // Cabeçalho padrão que o GenericStrategy sabe ler
    const header = "Data;Descrição;Valor;Tipo\n";

    const rows = transactions.map(t => {
        // Formatar data YYYY-MM-DD para DD/MM/YYYY (padrão BR esperado pelo parser genérico)
        const dateParts = t.date.split('-');
        const brDate = dateParts.length === 3 ? `${dateParts[2]}/${dateParts[1]}/${dateParts[0]}` : t.date;

        // Formatar valor para decimal com ponto (padrão genérico aceita)
        const amount = t.amount.toFixed(2);

        // Sanitizar descrição para evitar quebras de CSV
        const desc = t.description.replace(/;/g, ' ').trim();
        const type = (t.type || 'GMAIL_IMPORT').replace(/;/g, ' ');

        return `${brDate};${desc};${amount};${type}`;
    });

    return header + rows.join('\n');
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';
import { gmailService } from './GmailService';
import { adaptGmailToCsv } from './GmailAdapter';
import { XMarkIcon, EnvelopeIcon, SparklesIcon, CheckCircleIcon, ExclamationTriangleIcon, BoltIcon } from '../../components/Icons';

interface GmailModalProps {
    onClose: () => void;
    onSuccess: (csvContent: string) => void;
}

export const GmailModal: React.FC<GmailModalProps> = ({ onClose, onSuccess }) => {
    const [status, setStatus] = useState<'idle' | 'auth' | 'processing' | 'success' | 'error'>('idle');
    const [message, setMessage] = useState('Conecte sua conta para buscar comprovantes.');
    const [count, setCount] = useState(0);

    const startProcess = async () => {
        setStatus('auth');
        setMessage('Verificando permissões...');

        try {
            // 1. Iniciar OAuth no Frontend
            const { data, error } = await supabase.auth.signInWithOAuth({
                provider: 'google',
                options: {
                    scopes: 'https://www.googleapis.com/auth/gmail.readonly',
                    redirectTo: window.location.origin,
                    queryParams: { access_type: 'offline', prompt: 'consent' }
                }
            });

            if (error) throw error;

            // O redirecionamento acontecerá aqui, então o fluxo para.
            // A continuação deve ser tratada ao carregar a página (ver useEffect abaixo)

        } catch (e: any) {
            setStatus('error');
            setMessage(e.message || 'Erro na autenticação.');
        }
    };

    // Recuperação após redirect do OAuth
    useEffect(() => {
        const checkSession = async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (session?.provider_token) {
                // Temos o token! Iniciar processamento no Backend
                setStatus('processing');
                setMessage('Analisando e-mails recentes com IA...');

                try {
                    const transactions = await gmailService.syncEmails(session.provider_token);

                    if (transactions.length > 0) {
                        const csv = adaptGmailToCsv(transactions);
                        setCount(transactions.length);
                        setStatus('success');
                        setMessage(`${transactions.length} transações encontradas!`);

                        // Delay para leitura antes de fechar/sucesso
                        setTimeout(() => {
                            onSuccess(csv);
                            onClose();
                        }, 2000);
                    } else {
                        setStatus('error');
                        setMessage('Nenhum e-mail bancário relevante encontrado nos últimos dias.');
                    }
                } catch (err: any) {
                    setStatus('error');
                    setMessage('Erro ao processar e-mails. Tente novamente.');
                }
            }
        };

        // Apenas verifica se o modal for aberto com intuito de sync (pode ser controlado por props ou url params num app maior)
        // Aqui, simplificamos: se o usuário clicar no botão e já tiver token na sessão atual, ele usa.
    }, []);

    const executeSyncWithExistingSession = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.provider_token) {
            setStatus('processing');
            setMessage('Lendo e-mails...');
            try {
                const txs = await gmailService.syncEmails(session.provider_token);
                if (txs.length > 0) {
                    setCount(txs.length);
                    setStatus('success');
                    setTimeout(() => {
                        onSuccess(adaptGmailToCsv(txs));
                        onClose();
                    }, 1500);
                } else {
                    setStatus('error');
                    setMessage("Nenhum comprovante encontrado.");
                }
            } catch (e) {
                setStatus('error');
                setMessage("Falha na comunicação com o servidor.");
            }
        } else {
            startProcess();
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-2xl w-full max-w-sm border border-slate-200 dark:border-slate-700 overflow-hidden animate-scale-in text-center p-8">

                <div className="mb-6 flex justify-center">
                    <div className={`p-4 rounded-full ${status === 'error' ? 'bg-red-50 text-red-500' : 'bg-blue-50 text-brand-blue'} dark:bg-slate-700`}>
                        {status === 'processing' ? <SparklesIcon className="w-8 h-8 animate-pulse" /> : 
                         status === 'success' ? <CheckCircleIcon className="w-8 h-8 text-emerald-500" /> :
                         status === 'error' ? <ExclamationTriangleIcon className="w-8 h-8" /> :
                         <EnvelopeIcon className="w-8 h-8" />}
                    </div>
                </div>

                <h3 className="text-xl font-black text-slate-800 dark:text-white mb-2">Importar do Gmail</h3>
                <p className="text-sm text-slate-500 dark:text-slate-400 mb-8 min-h-[40px]">{message}</p>

                {status === 'idle' && (
                    <div className="space-y-3">
                        <button onClick={executeSyncWithExistingSession} className="w-full py-3 bg-brand-blue hover:bg-blue-600 text-white rounded-xl font-bold uppercase tracking-wide shadow-lg transition-all flex items-center justify-center gap-2">
                            <BoltIcon className="w-4 h-4" />
                            Iniciar Sincronização
                        </button>
                        <button onClick={onClose} className="text-slate-400 text-xs hover:text-slate-600 font-bold uppercase">Cancelar</button>
                    </div>
                )}

                {status === 'error' && (
                    <button onClick={onClose} className="px-6 py-2 border border-slate-200 text-slate-600 rounded-full font-bold text-xs uppercase hover:bg-slate-50">
                        Fechar
                    </button>
                )}
            </div>
        </div>
    );
};

