// ROTA 1: Processamento Seguro de Gmail (Backend-Driven)
app.post('/api/gmail/sync', async (req, res) => {
    if (!ai) return res.status(500).json({ error: "Serviço de IA não configurado." });

    const { accessToken } = req.body;
    if (!accessToken) return res.status(400).json({ error: "Token de acesso não fornecido." });

    try {
        console.log("[Gmail] Iniciando sincronização...");

        // 1. Buscar E-mails (Filtro Bancário)
        const emails = await fetchGmailMessages(
            accessToken, 
            'subject:(pix OR transferência OR comprovante OR recebido OR enviado) -category:promotions -category:social'
        );

        if (emails.length === 0) return res.json({ csv: "", count: 0 });

        // 2. Preparar Payload para Gemini
        const emailContext = emails.map(e => `
            ID: ${e.id}
            DATA: ${e.date}
            ASSUNTO: ${e.subject}
            CORPO: ${e.body.replace(/\s+/g, ' ')}
        `).join('\n---\n');

        const prompt = `
            Atue como um extrator de dados bancários rigoroso.
            Analise os e-mails abaixo e extraia transações financeiras.

            REGRAS DE OURO:
            1. Retorne APENAS transações confirmadas (Pix enviado/recebido, TEF, Pagamentos).
            2. Ignore e-mails de propaganda ou avisos gerais.
            3. Data deve ser YYYY-MM-DD.
            4. Valor numérico (positivo para entradas, negativo para saídas/pagamentos).
            5. Descrição deve conter o nome da contraparte ou o tipo da operação.

            INPUT:
            ${emailContext}
        `;

        // 3. Processar com Gemini
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            description: { type: Type.STRING },
                            amount: { type: Type.NUMBER },
                            type: { type: Type.STRING }
                        },
                        required: ["date", "description", "amount"]
                    }
                }
            }
        });

        const transactions = response.text ? JSON.parse(response.text) : [];
        console.log(`[Gmail] ${transactions.length} transações extraídas.`);

        // 4. Converter para CSV no Backend (O Frontend recebe o arquivo pronto)
        const csvContent = convertToCsv(transactions);

        res.json({ 
            csv: csvContent, 
            count: transactions.length 
        });

    } catch (error) {
        console.error("[Gmail] Erro no processamento:", error);
        res.status(500).json({ error: "Erro ao processar e-mails: " + error.message });
    }
});

