import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';
import { gmailService } from './GmailService';
import { XMarkIcon, EnvelopeIcon, SparklesIcon, CheckCircleIcon, ExclamationTriangleIcon, BoltIcon } from '../../components/Icons';

interface GmailModalProps {
    onClose: () => void;
    onSuccess: (csvContent: string) => void;
}

export const GmailModal: React.FC<GmailModalProps> = ({ onClose, onSuccess }) => {
    const [status, setStatus] = useState<'idle' | 'auth' | 'processing' | 'success' | 'error'>('idle');
    const [message, setMessage] = useState('Conecte sua conta para buscar comprovantes.');
    const [count, setCount] = useState(0);

    const startProcess = async () => {
        setStatus('auth');
        setMessage('Verificando permissões...');

        try {
            // 1. Iniciar OAuth no Frontend (Redirecionamento)
            const { data, error } = await supabase.auth.signInWithOAuth({
                provider: 'google',
                options: {
                    scopes: 'https://www.googleapis.com/auth/gmail.readonly',
                    redirectTo: window.location.origin,
                    queryParams: { access_type: 'offline', prompt: 'consent' }
                }
            });

            if (error) throw error;

        } catch (e: any) {
            setStatus('error');
            setMessage(e.message || 'Erro na autenticação.');
        }
    };

    // Recuperação após redirect do OAuth
    useEffect(() => {
        const checkSession = async () => {
            const { data: { session } } = await supabase.auth.getSession();

            // Se tiver token de provedor, assume que é o retorno do OAuth
            if (session?.provider_token) {
                setStatus('processing');
                setMessage('Processando e-mails no servidor...');

                try {
                    // Chama o backend para pegar o CSV pronto
                    const { csv, count } = await gmailService.syncEmails(session.provider_token);

                    if (count > 0 && csv) {
                        setCount(count);
                        setStatus('success');
                        setMessage(`${count} transações importadas com sucesso!`);

                        setTimeout(() => {
                            onSuccess(csv);
                            onClose();
                        }, 2000);
                    } else {
                        setStatus('error');
                        setMessage('Nenhum comprovante bancário encontrado nos últimos dias.');
                    }
                } catch (err: any) {
                    setStatus('error');
                    setMessage('Erro ao processar no servidor. Tente novamente.');
                }
            }
        };

        // Em um app real, usaríamos flags no localStorage para saber se o modal deve abrir no retorno.
        // Aqui simplificamos: se o componente montou e tem token, tenta processar (se o usuário acabou de logar).
        // Para evitar disparos indesejados, o usuário deve clicar no botão "Iniciar" se já estiver logado mas quiser sincronizar.
    }, []);

    const executeSyncWithExistingSession = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.provider_token) {
            setStatus('processing');
            setMessage('Lendo e-mails...');
            try {
                const { csv, count } = await gmailService.syncEmails(session.provider_token);
                if (count > 0 && csv) {
                    setCount(count);
                    setStatus('success');
                    setMessage(`${count} transações importadas!`);
                    setTimeout(() => {
                        onSuccess(csv);
                        onClose();
                    }, 1500);
                } else {
                    setStatus('error');
                    setMessage("Nenhum comprovante encontrado.");
                }
            } catch (e) {
                setStatus('error');
                setMessage("Falha na comunicação com o servidor.");
            }
        } else {
            startProcess();
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-2xl w-full max-w-sm border border-slate-200 dark:border-slate-700 overflow-hidden animate-scale-in text-center p-8">

                <div className="mb-6 flex justify-center">
                    <div className={`p-4 rounded-full ${status === 'error' ? 'bg-red-50 text-red-500' : 'bg-blue-50 text-brand-blue'} dark:bg-slate-700`}>
                        {status === 'processing' ? <SparklesIcon className="w-8 h-8 animate-pulse" /> : 
                         status === 'success' ? <CheckCircleIcon className="w-8 h-8 text-emerald-500" /> :
                         status === 'error' ? <ExclamationTriangleIcon className="w-8 h-8" /> :
                         <EnvelopeIcon className="w-8 h-8" />}
                    </div>
                </div>

                <h3 className="text-xl font-black text-slate-800 dark:text-white mb-2">Importar do Gmail</h3>
                <p className="text-sm text-slate-500 dark:text-slate-400 mb-8 min-h-[40px]">{message}</p>

                {status === 'idle' && (
                    <div className="space-y-3">
                        <button onClick={executeSyncWithExistingSession} className="w-full py-3 bg-brand-blue hover:bg-blue-600 text-white rounded-xl font-bold uppercase tracking-wide shadow-lg transition-all flex items-center justify-center gap-2">
                            <BoltIcon className="w-4 h-4" />
                            Iniciar Sincronização
                        </button>
                        <button onClick={onClose} className="text-slate-400 text-xs hover:text-slate-600 font-bold uppercase">Cancelar</button>
                    </div>
                )}

                {status === 'error' && (
                    <button onClick={onClose} className="px-6 py-2 border border-slate-200 text-slate-600 rounded-full font-bold text-xs uppercase hover:bg-slate-50">
                        Fechar
                    </button>
                )}
            </div>
        </div>
    );
};

